-- ---- Column Comments ----
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. DWH note: column renamed from RealCID (Dim_Customer) for eMoney context; joins back via CID=RealCID. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `GCID` COMMENT 'Group Customer ID - cross-product identity key linking the same person across eToro products/entities. NULL for older accounts predating GCID introduction. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `ClientRiskDate` COMMENT 'Date the current ClientRisk class was first assigned. Preserved across daily runs while class is unchanged; reset to @Date (today) when class changes. For PEP overrides: ISNULL(last history date, @Date). For manual overrides: ExecutedDate from override sheet. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `ClientRisk` COMMENT 'Customer AML risk classification. Values: Low (score <= @RiskLowerCut), Medium (> LowerCut <= UpperCut), High ( >=  @RiskUpperCut), Error (unresolvable). Thresholds are dynamic (ParameterID=98/99 in Fivetran classification table). Overridden to ''High'' for PEP customers; overridden to custom value for manual override CIDs. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `ClientRiskAssignmentType` COMMENT 'Method by which ClientRisk was assigned. Values: ''Regular'' (algorithm), ''PEP Override'' (ScreeningStatus=''PEP''), ''Manual Override'' (CID in override Google Sheet). Override types take precedence over Regular in that order. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `Risk_Final_Result` COMMENT 'Weighted risk score: SUM(P1_RiskID×P1_Weight + P2_RiskID×P2_Weight + … + P32_RiskID×P32_Weight). P10 always contributes 0 (cancelled). Missing parameters contribute 99999-code row from classification table. Used to derive ClientRisk via threshold comparison. NOT modified by override logic - a PEP-forced customer retains the algorithm score. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `PreviousClientRisk` COMMENT 'ClientRisk from the most recent row in eMoney_Customer_Risk_Assessment_History (latest ClientRiskDate DESC). ISNULL -> ''None'' for customers with no history. Used in ClientRiskDate preservation logic and History insert filter. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `PreviousClientRiskDate` COMMENT 'ClientRiskDate from the most recent row in eMoney_Customer_Risk_Assessment_History. NULL for customers with no history. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified, 1=partial, 2=intermediate, 3=fully verified. Default=0. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsValidCustomer` COMMENT 'DWH-computed validity flag from Dim_Customer. 1 when not Internal (PlayerLevelID != 4), not label 30/26, and CountryID != 250. Used for filtering non-standard customer profiles. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsDepositor` COMMENT '1 if the customer has made at least one deposit on the eToro trading platform. Sourced from Dim_Customer. Used in certain eTM analytics filters. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `AccountType` COMMENT 'Trading platform account type display name, resolved from DWH_dbo.Dim_AccountType via AccountTypeID. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `Regulation` COMMENT 'Regulatory jurisdiction display name, resolved from DWH_dbo.Dim_Regulation via RegulationID. Top values: CySEC, FCA, BVI, ASIC, GAML. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `Club` COMMENT 'eToro Club tier display name, resolved from DWH_dbo.Dim_PlayerLevel via PlayerLevelID. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `ClientAge` COMMENT 'Customer''s age in years at SP execution date, computed as DATEDIFF(YEAR, BirthDate, @Date). Sentinel 99999 used when age > 120, <= 0, or BirthDate is NULL. This integer value feeds into P1 classification. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `DateOfBirth` COMMENT 'Customer date of birth. Used in LinkedAccountHash1 for duplicate detection and in KYC age verification. DWH note: CAST from datetime to date (time component removed); column renamed from BirthDate. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `DateOfReg` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). DWH note: CAST from datetime to date; column renamed from RegisteredReal in Dim_Customer. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `DateOfFTD` COMMENT 'Date of first trading platform deposit. CAST(FirstDepositDate AS DATE) from Dim_Customer. Sentinel ''19000101'' for non-depositors. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `BusinessDuration` COMMENT 'Bucketed tenure as eToro depositor, based on years since DateOfFTD. Values: 99999 (no FTD or sentinel ''19000101''), 1 (<1 year), 2 (1 - 3 years), 3 (>3 years). Feeds into P11 classification. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryAddress` COMMENT 'KYC address country display name, resolved from #dim_country (Dim_Country) via CountryID. Reflects the customer''s declared residential country. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryCitizenship` COMMENT 'Citizenship country display name, resolved from #dim_country via CitizenshipCountryID. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryPOB` COMMENT 'Place of birth country display name, resolved from #dim_country via POBCountryID. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryTIN` COMMENT 'Tax identification number (TIN) country display name. Resolved via a prioritised lookup: address-matching country > HRC country > non-HRC country from BI_DB_dbo.External_UserApiDB_Customer_ExtendedUserField (FieldId=6). NULL when no TIN country is registered. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryAddress_IsHRC` COMMENT 'High-risk country flag for the KYC address country. 0=not high risk, 1=high risk, 99999=not classified in CRA mapping. Sourced from Fivetran country risk map. Feeds into P2 classification. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryCitizenship_IsHRC` COMMENT 'High-risk country flag for the citizenship country. 0=not high risk, 1=high risk, 99999=not classified. Feeds into P3 classification. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `CountryPOB_IsHRC` COMMENT 'High-risk country flag for the place of birth country. 0=not high risk, 1=high risk, 99999=not classified. Feeds into P4 classification. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
