ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `AccountStatus` COMMENT 'Trading platform account lifecycle status display name, resolved from DWH_dbo.Dim_AccountStatus via AccountStatusID. (Tier 2 - SP_eMoney_Customer_Risk_Assessment)';
